    slug: "ai-governance-cybersecurity",
    title: "AI Governance Starts as Cybersecurity Governance",
    subtitle: "Why effective AI oversight builds on existing cybersecurity frameworks",
    date: "2026-03-25",
    dateFormatted: "March 25, 2026",
    category: "AI Governance",
    tags: ["Ai governance","Cybersecurity","Board governance","Eu ai act","Ciso","Risk management"],
    readingTime: "7 min read",
    featured: false,
    heroImage: "/images/articles/ai-governance-cybersecurity.svg",
    
    linkedinUrl: "",
